import { normalize } from 'viem/ens';

const name = normalize('alice.eth');
const address = await client.getEnsAddress({ name });
if (!address) throw new Error('ENS name not registered');

// Reverse check (defend against unidirectional spoofing)
const reverseName = await client.getEnsName({ address });
if (reverseName !== name) {
  throw new Error('ENS reverse mismatch -- possible spoof');
}
